import React from 'react'
import c from './add.module.scss'
import { Icons } from '../../assets/icons'
import { API } from '../../api'

const AddProfit = ({ setActive }) => {
  const [count, setCount] = React.useState(1)
  const [data, setData] = React.useState([{name: '', price: '' }])

  const handleChange = (index, field, value) => {
    const newData = [...data]
    newData[index] = { ...newData[index], [field]: value }
    setData(newData)
  }

  const handleAddForm = () => {
    setCount(prev => prev + 1)
    setData(prev => [...prev, { name: '', amount: '', quantity: '', price: '', unit: '' }]);
  }

  const handleSave = (value) => {
    API.postExpenses(value)
      .then(() => {
        setActive(false)
      })
      .catch(err => console.error(err))
  };

  console.log(data);

  return (
    <div className={c.addExpense}>
      <div className={c.addExpense__header}>
        <h2>Добавить прибыли</h2>
      </div>

      {Array.from({ length: count }).map((_, index) => (
        <div
          key={index}
          className={c.addExpense__form}
        >
          <div className={c.addExpense__form__item}>
            <label htmlFor={`name-${index}`}>Наименование расхода</label>
            <input
              type="text"
              id={`name-${index}`}
              placeholder="Введите наимаенование"
              value={data[index]?.name || ''}
              onChange={e => handleChange(index, 'name', e.target.value)}
            />
          </div>
          <div className={c.addExpense__form__item}>
            <label htmlFor={`price-${index}`}>Сумма</label>
            <input
              type="number"
              id={`price-${index}`}
              placeholder="Введите Сумма"
              value={data[index]?.price || ''}
              onChange={e => handleChange(index, 'price', e.target.value)}
            />
          </div>
        </div>
      ))}

      <button onClick={handleAddForm}>
        <img src={Icons.plus} alt="plus" />
        Добавить наименование
      </button>

      <div className={c.res}>
        <button onClick={() => setActive(false)}>
          Отменить
        </button>
        <button onClick={() => handleSave(data)}>
          <img src={Icons.addGreen} alt="add" />
          Сохранить
        </button>
      </div>
    </div>
  )
}

export default AddProfit
